// Validate and build the system + user prompt for Ollama.
const results = [];

for (const item of $input.all()) {
  const ev = item.json;

  const required = ['schema_version', 'event_id', 'correlation_id', 'source', 'type', 'occurred_at'];
  const missing = required.filter(f => !ev[f]);
  if (missing.length > 0) {
    throw new Error(`Missing fields: ${missing.join(', ')}`);
  }

  const systemPrompt = `You are Digital Clone, an AI assistant running on the owner's local hardware. Nothing leaves this machine.

Rules:
1. You have ZERO authority to execute trades, move money, or take irreversible actions.
2. Use ONLY provided data. Never invent facts.
3. Be concise and direct.

Routing paths (choose one based on the user's request):
- "alpha": informational reply needed → draft a concise reply
- "beta": task/follow-up to log → acknowledge
- "deny": request violates a guardrail → refuse politely

Output ONLY valid JSON with this structure:
{"schema_version":"1.0","correlation_id":"CORR_ID","path":"alpha|beta|deny","summary":"one-line summary","reply":{"text":"reply message","format":"plain"},"confidence":0.9}`;

  const userPrompt = `User message from ${ev.source}: "${(ev.text || '').substring(0, 2000)}"
Sender: ${ev.actor ? ev.actor.display_name : 'unknown'} (${ev.source})
Correlation ID: ${ev.correlation_id}
Type: ${ev.type}

Determine the routing path and generate the JSON response.`;

  results.push({
    json: {
      ...ev,
      _system_prompt: systemPrompt,
      _user_prompt: userPrompt
    }
  });
}

return results;

// Parse Ollama response and build ai-output contract.
const results = [];

for (const item of $input.all()) {
  const d = item.json;
  let aiOutput;

  // Ollama /api/generate returns { "response": "..." }
  const rawResponse = d.response || d._ollama_response || '';

  try {
    // Try to extract JSON from the response
    let jsonStr = String(rawResponse).trim();
    const fenceMatch = jsonStr.match(/```(?:json)?\s*([\s\S]*?)```/);
    if (fenceMatch) jsonStr = fenceMatch[1].trim();
    aiOutput = JSON.parse(jsonStr);
  } catch (e) {
    // Fallback: use the raw text as alpha reply
    aiOutput = {
      schema_version: "1.0",
      correlation_id: d.correlation_id || '',
      path: "alpha",
      summary: "AI response",
      reply: { text: rawResponse.substring(0, 1500), format: "plain" },
      confidence: 0.7
    };
  }

  aiOutput.correlation_id = d.correlation_id || aiOutput.correlation_id;
  aiOutput.schema_version = "1.0";
  if (!['alpha', 'beta', 'deny'].includes(aiOutput.path)) {
    aiOutput.path = 'gamma';
  }
  aiOutput.summary = aiOutput.summary || 'Processed';
  if (aiOutput.reply && !aiOutput.reply.format) aiOutput.reply.format = 'plain';
  if (!aiOutput.actions) aiOutput.actions = [];
  if (!aiOutput.guardrail) aiOutput.guardrail = { triggered: aiOutput.path === 'deny' };
  if (!aiOutput.confidence) aiOutput.confidence = 0.8;

  results.push({
    json: {
      event_id: d.event_id,
      correlation_id: d.correlation_id,
      source: d.source,
      type: d.type,
      occurred_at: d.occurred_at,
      actor: d.actor,
      channel: d.channel,
      text: d.text,
      data: d.data,
      attachments: d.attachments,
      metadata: d.metadata,
      raw: d.raw,
      ai_path: aiOutput.path,
      ai_summary: aiOutput.summary,
      ai_reply_text: aiOutput.reply ? aiOutput.reply.text : null,
      ai_reply_format: aiOutput.reply ? (aiOutput.reply.format || 'plain') : null,
      ai_actions: aiOutput.actions,
      ai_guardrail_triggered: aiOutput.guardrail ? aiOutput.guardrail.triggered : false,
      ai_guardrail_rule: aiOutput.guardrail ? (aiOutput.guardrail.rule || null) : null,
      ai_guardrail_message: aiOutput.guardrail ? (aiOutput.guardrail.message || null) : null,
      ai_confidence: aiOutput.confidence
    }
  });
}

return results;
